#include<bits/stdc++.h>
using namespace std;
int x1, x2, mid, n;
char c;
int main() {
	cin >> n >> c;
	x1 = n / 2;
	x2 = n / 2;
	mid = c - n / 2;
	for (int i = 1; i <= n / 2 + 1; i++) {
		for (int j = 0; j < n; j++) {
			if (j <= x2 && x1 <= j) {
				if (j >= n / 2) {
					cout << char(mid + (x2 - j));
				} else {
					cout << char(mid + (j - x1));
				}
			} else {
				cout << ".";
			}
		}
		x2++;
		x1--;
		cout << "\n";
	}
	x2--;
	x1++;
	for (int i = 1; i <= n / 2; i++) {
		x2--;
		x1++;
		for (int j = 0; j < n; j++) {
			if (j <= x2 && x1 <= j) {
				if (j >= n / 2) {
					cout << char(mid + (x2 - j));
				} else {
					cout << char(mid + (j - x1));
				}
			} else {
				cout << ".";
			}
		}

		cout << "\n";
	}
}
